     4Ôćĺimport { SessionService } from '$lib/server/sessions/session-service.js';
     5Ôćĺ
     6Ôćĺexport async function _handleGetSessions(service: SessionService, url: URL): Promise<Response> {
     7Ôćĺ	const containerId = url.searchParams.get('container') ?? undefined;
     8Ôćĺ	const sessions = await service.list(containerId);
     9Ôćĺ	return jsonResponse(sessions);
    10Ôćĺ}
    11Ôćĺ
    12Ôćĺinterface CreateSessionBody {
    13Ôćĺ	name?: unknown;
    14Ôćĺ	type?: unknown;
    15Ôćĺ	containerId?: unknown;
    16Ôćĺ}
    17Ôćĺ
    18Ôćĺexport async function _handlePostSession(
    19Ôćĺ	request: Request,
    20Ôćĺ	service: SessionService
    21Ôćĺ): Promise<Response> {
    22Ôćĺ	let body: CreateSessionBody;
    23Ôćĺ	try {
    24Ôćĺ		body = await parseRequestBody<CreateSessionBody>(request);
    25Ôćĺ	} catch {
    26Ôćĺ		return errorResponse('Request body is required', 400);
    27Ôćĺ	}
    28Ôćĺ
    29Ôćĺ	if (typeof body.name !== 'string') {
    30Ôćĺ		return errorResponse('name is required and must be a string', 400);
    31Ôćĺ	}
    32Ôćĺ	if (typeof body.type !== 'string') {
    33Ôćĺ		return errorResponse('type is required and must be a string', 400);
    34Ôćĺ	}
    35Ôćĺ	if (typeof body.containerId !== 'string') {
    36Ôćĺ		return errorResponse('containerId is required and must be a string', 400);
    37Ôćĺ	}
    38Ôćĺ
    39Ôćĺ	const nameValidation = validateRequired(body.name, 'name');
    40Ôćĺ	if (!nameValidation.success) {
    41Ôćĺ		return errorResponse(nameValidation.error, 400);
    42Ôćĺ	}
    43Ôćĺ
    44Ôćĺ	const typeValidation = validateSessionType(body.type);
    45Ôćĺ	if (!typeValidation.success) {
    46Ôćĺ		return errorResponse(typeValidation.error, 400);
    47Ôćĺ	}
    48Ôćĺ
    49Ôćĺ	const containerIdValidation = validateRequired(body.containerId, 'containerId');
    50Ôćĺ	if (!containerIdValidation.success) {
    51Ôćĺ		return errorResponse(containerIdValidation.error, 400);
    52Ôćĺ	}
    53Ôćĺ
    54Ôćĺ	try {
    55Ôćĺ		const session = await service.create({
    56Ôćĺ			name: body.name,
    57Ôćĺ			type: typeValidation.value,
    58Ôćĺ			containerId: body.containerId
    59Ôćĺ		});
    60Ôćĺ		return jsonResponse(session, 201);
    61Ôćĺ	} catch (err) {
    62Ôćĺ		const message = err instanceof Error ? err.message : 'Failed to create session';
    63Ôćĺ		if (message.includes('not found')) {
    64Ôćĺ			return errorResponse(message, 404);
    65Ôćĺ		}
    66Ôćĺ		return errorResponse(message, 500);
    67Ôćĺ	}
    68Ôćĺ}
    69Ôćĺ
