    71Ôćĺ	const { getSessionService } = await import('$lib/server/sessions/singleton.js');
    72Ôćĺ	return _handleGetSessions(getSessionService(), url);
    73Ôćĺ};
    74Ôćĺ
    75Ôćĺexport const POST: RequestHandler = async ({ request }) => {
