    28Ôćĺ	}
    29Ôćĺ
    30Ôćĺ	if (typeof body.name !== 'string') {
    31Ôćĺ		return errorResponse('name is required and must be a string', 400);
    32Ôćĺ	}
    33Ôćĺ	if (typeof body.templateId !== 'string') {
    34Ôćĺ		return errorResponse('templateId is required and must be a string', 400);
    35Ôćĺ	}
    36Ôćĺ
    37Ôćĺ	const nameValidation = validateContainerName(body.name);
    38Ôćĺ	if (!nameValidation.success) {
    39Ôćĺ		return errorResponse(nameValidation.error, 400);
    40Ôćĺ	}
    41Ôćĺ
    42Ôćĺ	const templateValidation = validateRequired(body.templateId, 'templateId');
    43Ôćĺ	if (!templateValidation.success) {
    44Ôćĺ		return errorResponse(templateValidation.error, 400);
    45Ôćĺ	}
    46Ôćĺ
    47Ôćĺ	const config = (body.config ?? {}) as ContainerConfig;
    48Ôćĺ
    49Ôćĺ	try {
    50Ôćĺ		const container = await service.create({
    51Ôćĺ			name: body.name,
    52Ôćĺ			templateId: body.templateId,
    53Ôćĺ			config
    54Ôćĺ		});
    55Ôćĺ		return jsonResponse(container, 201);
    56Ôćĺ	} catch (err) {
    57Ôćĺ		const message = err instanceof Error ? err.message : 'Failed to create container';
    58Ôćĺ		if (message.includes('already exists')) {
    59Ôćĺ			return errorResponse(`Container name '${body.name}' is already taken`, 409);
    60Ôćĺ		}
    61Ôćĺ		return errorResponse(message, 500);
    62Ôćĺ	}
    63Ôćĺ}
